/* == EXEMPLE =======================================
 * Broker simple : uppercase transformation
 * ================================================= */
void example_broker(void) {
    struct mq_attr a = { .mq_maxmsg = 5, .mq_msgsize = 64 };
    mqd_t in = mq_open("/kf_ex_in", O_CREAT|O_RDWR, 0644, &a);
    mqd_t out = mq_open("/kf_ex_out", O_CREAT|O_RDWR, 0644, &a);
    mq_send(in, "hello", 5, 0);
    char buf[64]; ssize_t n = mq_receive(in, buf, sizeof(buf), NULL);
    buf[n] = '\0';
    for (int i = 0; buf[i]; i++) buf[i] -= 32;
    mq_send(out, buf, strlen(buf), 0);
    n = mq_receive(out, buf, sizeof(buf), NULL);
    buf[n] = '\0';
    printf("Broker: %s\n", buf);
    mq_close(in); mq_close(out);
    mq_unlink("/kf_ex_in"); mq_unlink("/kf_ex_out");
}
